module RefModule(
    input clk,
    input reset,
    output reg [7:0] q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset) begin
            // Synchronous reset: Reset the counter to 8'b00000001
            q <= 8'b00000001;
        end else begin
            // Johnson counter: Shift left and invert the LSB
            q <= {q[6:0], ~q[7]};
        end
    end

endmodule
